var getStrongest = function(arr, k) {
    arr.sort((a, b) => a - b);
    const m = arr[Math.floor((arr.length - 1) / 2)];
    arr.sort((a, b) => {
        const da = Math.abs(a - m), db = Math.abs(b - m);
        if (da !== db) return db - da;
        return b - a;
    });
    return arr.slice(0, k);
};
